<?php $__env->startSection('title','Reviews'); ?>
<?php $__env->startSection('content'); ?><div class="table-card"><table class="table"><tr><th>Product</th><th>Customer</th><th>Rating</th><th>Comment</th><th>Approved</th><th></th></tr><?php $__currentLoopData = $reviews; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $review): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($review->product->name); ?></td><td><?php echo e($review->user->name); ?></td><td><?php echo e($review->rating); ?></td><td><?php echo e($review->comment); ?></td><td><?php echo e($review->is_approved?'Yes':'No'); ?></td><td><form class="d-inline" method="post" action="<?php echo e(route('admin.reviews.update',$review)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('PUT'); ?><input type="hidden" name="is_approved" value="<?php echo e($review->is_approved?0:1); ?>"><button class="btn btn-sm btn-outline-primary"><?php echo e($review->is_approved?'Hide':'Approve'); ?></button></form><form class="d-inline" method="post" action="<?php echo e(route('admin.reviews.destroy',$review)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('DELETE'); ?><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></table><?php echo e($reviews->links()); ?></div><?php $__env->stopSection(); ?>

